import type * as React from 'react';
import type { DefaultSizeType, ElementOf } from '../util';
export type ValueType = ElementOf<[number | string]>;
/**
 * @public
 */
export interface InputNumberProps<T extends ValueType = ValueType> {
    /**
     * 自定义 id
     */
    id?: string;
    /**
     * 自定义样式
     */
    style?: React.CSSProperties;
    /**
     * 自定义类名
     */
    className?: string;
    /**
     * 最小值（不可受控使用）
     * @defaultValue  `Number.MIN_SAFE_INTEGER`
     */
    min?: number;
    /**
     * 最大值（不可受控使用）
     * @defaultValue `Number.MAX_SAFE_INTEGER`
     */
    max?: number;
    /**
     * 输入框模式
     * @defaultValue `default`
     */
    mode?: 'default' | 'stepper';
    /**
     * 每次改变步数，可以为小数
     * @defaultValue 1
     */
    step?: number;
    /**
     * 输入框大小
     * @defaultValue `medium`
     */
    size?: DefaultSizeType;
    /**
     * 是否是错误状态
     */
    error?: boolean;
    /**
     * 当前值
     */
    value?: T;
    /**
     * 初始值
     */
    defaultValue?: T;
    /**
     * tabIndex
     * @deprecated not used
     */
    tabIndex?: number;
    /**
     * 是否为禁用状态
     * @defaultValue false
     */
    disabled?: boolean;
    /**
     * 是否为只读状态
     * @defaultValue false
     */
    readOnly?: boolean;
    /**
     * 是否自动获取焦点
     * @defaultValue false
     */
    autoFocus?: boolean;
    /**
     * 数值精度
     */
    precision?: number;
    /**
     * 输入框中的默认文案
     */
    placeholder?: string;
    /**
     * 是否自动把输入的字符过滤, 只保留数字
     */
    onlyNumber?: boolean;
    /**
     * 指定输入框展示值的格式
     */
    formatter?: (value?: number | string) => string;
    /**
     * 按下回车的回调
     */
    onPressEnter?: React.KeyboardEventHandler<HTMLInputElement>;
    /**
     * 点击上下箭头的回调
     */
    onStep?: (value: T, info: {
        offset: number;
        type: 'up' | 'down';
    }) => void;
    /**
     * 变化回调
     */
    onChange?: (value?: number) => void;
    /**
     * 指定从`formatter`里转换回数字的方式，和`formatter`搭配使用
     */
    parser?: (displayValue: string | undefined) => string;
    /**
     * 鼠标移入事件回调
     */
    onMouseEnter?: (e: React.MouseEvent<HTMLDivElement, MouseEvent>) => void;
    /**
     * 鼠标移出事件回调
     */
    onMouseLeave?: (e: React.MouseEvent<HTMLDivElement, MouseEvent>) => void;
    /**
     * 输入框获取焦点事件回调
     */
    onFocus?: (e: React.FocusEvent<HTMLInputElement>) => void;
    /**
     * 输入框失去焦点事件回调
     */
    onBlur?: (e: React.FocusEvent<HTMLInputElement>) => void;
    /**
     * 点击事件
     */
    onClick?: (e: React.MouseEvent<HTMLDivElement, MouseEvent>) => void;
    /**
     * 额外的前缀
     */
    addonBefore?: React.ReactNode;
    /**
     * 额外的后缀
     */
    addonAfter?: React.ReactNode;
    /**
     * 是否显示控制按钮
     * @defaultValue true
     */
    controls?: boolean;
}
